import{_ as t,C as n,o,c as l,j as a,a as i,E as r,a3 as h}from"./chunks/framework.CLYqdwvN.js";const v=JSON.parse('{"title":"Update Check","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/update-check.md","filePath":"advanced/update-check.md"}'),c={name:"advanced/update-check.md"},d={id:"update-check",tabindex:"-1"};function p(k,e,g,u,m,f){const s=n("VersionBadge");return o(),l("div",null,[a("h1",d,[e[0]||(e[0]=i("Update Check ",-1)),r(s,{v:"0.9.0"}),e[1]||(e[1]=i()),e[2]||(e[2]=a("a",{class:"header-anchor",href:"#update-check","aria-label":'Permalink to "Update Check <VersionBadge v="0.9.0" />"'},"​",-1))]),e[3]||(e[3]=h('<p>amoxide checks crates.io periodically for a newer release and prints a one-line nudge when one exists. The check is <strong>non-blocking</strong>, <strong>cached for 24 hours</strong>, and <strong>fully opt-out</strong>.</p><h2 id="what-you-see" tabindex="-1">What you see <a class="header-anchor" href="#what-you-see" aria-label="Permalink to &quot;What you see&quot;">​</a></h2><p>When a newer version is available, the listing commands (<code>am ls</code>, <code>am la</code>, <code>am profile list</code>) print a single line to <strong>stderr</strong> after the listing:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>am: 💡 a new version is available: v0.9.0 -&gt; visit https://github.com/sassman/amoxide-rs/releases</span></span></code></pre></div><p>When you are already on the latest version, nothing is printed.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><ul><li>The first time you run a listing command, amoxide spawns a detached background process that calls crates.io. The current <code>am ls</code> output prints immediately — you wait for nothing.</li><li>The result is written to a local cache file under <code>~/.cache/amoxide/update-check.toml</code>.</li><li>Subsequent listing calls read that cache. If it&#39;s older than 24 hours, a fresh background check is kicked off and the cached result (if any) is shown in the meantime.</li><li>All errors (offline, DNS failure, timeout, malformed response) are swallowed silently. The listing command never fails because of the update check.</li></ul><p>Because the nudge goes to stderr, scripts that pipe <code>am ls</code> continue to work unchanged:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-alias</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # unaffected by the nudge</span></span></code></pre></div><h2 id="disabling-the-check" tabindex="-1">Disabling the check <a class="header-anchor" href="#disabling-the-check" aria-label="Permalink to &quot;Disabling the check&quot;">​</a></h2><p>You can disable the update check via <strong>config</strong> (once-and-done) or <strong>environment variable</strong> (per-invocation, ideal for CI).</p><h3 id="config-config-amoxide-config-toml" tabindex="-1">Config: <code>~/.config/amoxide/config.toml</code> <a class="header-anchor" href="#config-config-amoxide-config-toml" aria-label="Permalink to &quot;Config: `~/.config/amoxide/config.toml`&quot;">​</a></h3><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">check = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p>When <code>check = false</code>, neither the cache read nor the background spawn happens. No network call is ever made, and no cache file is created.</p><h3 id="environment-am-no-update-check" tabindex="-1">Environment: <code>AM_NO_UPDATE_CHECK</code> <a class="header-anchor" href="#environment-am-no-update-check" aria-label="Permalink to &quot;Environment: `AM_NO_UPDATE_CHECK`&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">AM_NO_UPDATE_CHECK</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span></span></code></pre></div><p>Set this to any non-empty value to skip the check for one invocation. Useful for CI environments where you neither want a network call nor a config edit.</p><h2 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h2><p>The check sends one HTTPS request to <code>https://crates.io/api/v1/crates/amoxide</code>. The only data leaving your machine is the crate name and the User-Agent that ureq sets. No telemetry, no identifiers, no version of your local binary is reported.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/_preview/126/advanced/config-files">Config Files</a> — full TOML reference</li></ul>',21))])}const y=t(c,[["render",p]]);export{v as __pageData,y as default};
